@namespace sv_a2434daba9ac4eb287d556620d61403a.Components.Pages.Settings
@using sv_a2434daba9ac4eb287d556620d61403a.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Profile</h4>

@if (_loading)
{
    <p class="text-muted">Loading profile…</p>
}
else
{
    @if (_statusMessage is not null)
    {
        <div class="alert @(_statusIsError ? "alert-danger" : "alert-success") alert-dismissible py-2">
            @_statusMessage
            <button type="button" class="btn-close btn-sm" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>
        <div class="col-md-4">
            <div class="avatar-preview text-center">
                <div class="avatar-frame mb-2">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" class="rounded-circle" width="120" height="120" />
                    }
                    else
                    {
                        <div class="avatar-placeholder rounded-circle">👤</div>
                    }
                </div>
                <small class="text-muted text-break">@_avatarUrl</small>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveChanges" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="DiscardChanges" disabled="@_saving">
            Discard Changes
        </button>
    </div>
}

@code {
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    private UserProfile? _savedProfile;
    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;
    private bool _statusIsError;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        ApplyProfile(profile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _savedProfile = profile;
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveChanges()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _statusMessage = "Profile saved successfully!";
            _statusIsError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Error saving profile: {ex.Message}";
            _statusIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _statusMessage = null;
    }
}

.avatar-preview {
    padding: 1rem;
}

.avatar-frame {
    display: inline-block;
}

.avatar-placeholder {
    width: 120px;
    height: 120px;
    background: var(--bs-secondary-bg, #e9ecef);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    font-size: 3rem;
}

@namespace sv_a2434daba9ac4eb287d556620d61403a.Components.Pages.Settings
@using sv_a2434daba9ac4eb287d556620d61403a.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Notifications</h4>

@if (_loading)
{
    <p class="text-muted">Loading notification preferences…</p>
}
else
{
    @if (_statusMessage is not null)
    {
        <div class="alert alert-success alert-dismissible py-2">
            @_statusMessage
            <button type="button" class="btn-close btn-sm" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="mb-4">
        <h6>General</h6>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <div class="mb-4">
        <h6>Muted Channels</h6>
        @if (_allChannels.Count == 0)
        {
            <p class="text-muted small">No channels available.</p>
        }
        else
        {
            @foreach (var channel in _allChannels)
            {
                <div class="form-check mb-1">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@_mutedChannels.Contains(channel)"
                           @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                    <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                </div>
            }
        }
    </div>

    <button class="btn btn-primary" @onclick="SavePreferences" disabled="@_saving">
        @(_saving ? "Saving…" : "Save Preferences")
    </button>
}

@code {
    /// <summary>
    /// Full list of channels available for muting.
    /// Passed from the parent or populated from the loaded prefs.
    /// </summary>
    [Parameter] public List<string> AvailableChannels { get; set; } = ["general", "announcements", "engineering", "design", "random"];

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private List<string> _allChannels = [];

    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];

        // Merge available channels with any already-muted channels the user has
        _allChannels = [.. AvailableChannels.Union(prefs.MutedChannels).Distinct().Order()];
        _loading = false;
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                [.. _mutedChannels]);
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _statusMessage = "Notification preferences saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}

@namespace sv_a2434daba9ac4eb287d556620d61403a.Components.Pages.Settings
@using sv_a2434daba9ac4eb287d556620d61403a.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Security</h4>

@if (_loading)
{
    <p class="text-muted">Loading security settings…</p>
}
else
{
    @if (_statusMessage is not null)
    {
        <div class="alert @(_statusIsError ? "alert-danger" : "alert-success") alert-dismissible py-2">
            @_statusMessage
            <button type="button" class="btn-close btn-sm" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <div class="card mb-3">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <strong>Two-Factor Authentication</strong>
                <div class="small text-muted mt-1">
                    Status:
                    @if (_twoFactorEnabled)
                    {
                        <span class="badge bg-success">Enabled</span>
                    }
                    else
                    {
                        <span class="badge bg-secondary">Disabled</span>
                    }
                </div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
            </div>
        </div>
    </div>

    @if (_lastPasswordChange.HasValue)
    {
        <p class="text-muted small">
            Last password change: @_lastPasswordChange.Value.ToString("MMMM d, yyyy 'at' h:mm tt")
        </p>
    }

    <h5 class="mt-4 mb-3">Active Sessions</h5>
    <div class="table-responsive">
        <table class="table table-hover align-middle">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in _sessions)
                {
                    <tr>
                        <td>@session.Device</td>
                        <td>@session.Location</td>
                        <td>@session.LastActive.ToString("MMM d, yyyy h:mm tt")</td>
                        <td>
                            @if (session != _sessions[0])
                            {
                                <button class="btn btn-sm btn-outline-danger"
                                        @onclick="() => PromptRevoke(session)">
                                    Revoke
                                </button>
                            }
                            else
                            {
                                <span class="badge bg-info">Current</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    <RevokeSessionDialog Visible="_revokeTarget is not null"
                         Device="@(_revokeTarget?.Device ?? "")"
                         Location="@(_revokeTarget?.Location ?? "")"
                         OnConfirm="ConfirmRevoke"
                         OnCancel="CancelRevoke" />
}

@code {
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private ActiveSession? _revokeTarget;

    private bool _loading = true;
    private string? _statusMessage;
    private bool _statusIsError;

    protected override async Task OnInitializedAsync()
    {
        await LoadSettings();
        _loading = false;
    }

    private async Task LoadSettings()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = [.. settings.Sessions];
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
    }

    private void PromptRevoke(ActiveSession session)
    {
        _revokeTarget = session;
    }

    private void CancelRevoke()
    {
        _revokeTarget = null;
    }

    private async Task ConfirmRevoke()
    {
        if (_revokeTarget is null) return;
        var sessionId = _revokeTarget.Id;
        _revokeTarget = null;

        try
        {
            await SettingsService.RevokeSessionAsync(sessionId);
            _sessions.RemoveAll(s => s.Id == sessionId);
            _statusMessage = "Session revoked successfully.";
            _statusIsError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to revoke session: {ex.Message}";
            _statusIsError = true;
        }
    }
}

@namespace sv_a2434daba9ac4eb287d556620d61403a.Components.Pages.Settings
@using sv_a2434daba9ac4eb287d556620d61403a.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Appearance</h4>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    @if (_statusMessage is not null)
    {
        <div class="alert alert-success alert-dismissible py-2">
            @_statusMessage
            <button type="button" class="btn-close btn-sm" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-7">
            <div class="mb-4">
                <h6>Theme</h6>
                @foreach (var theme in _themes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme.ToLower()}")"
                               value="@theme"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme.ToLower()}")">@theme</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Font Size</h6>
                @foreach (var size in _fontSizes)
                {
                    <div class="form-check form-check-inline">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size.ToLower()}")"
                               value="@size"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size.ToLower()}")">@size</label>
                    </div>
