{"file_text": "@namespace sv_a2434daba9ac4eb287d556620d61403a.Components.Pages.Settings
@using sv_a2434daba9ac4eb287d556620d61403a.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Appearance</h4>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    @if (_statusMessage is not null)
    {
        <div class="alert alert-success alert-dismissible py-2">
            @_statusMessage
            <button type="button" class="btn-close btn-sm" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-7">
            <div class="mb-4">
                <h6>Theme</h6>
                @foreach (var theme in _themes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme.ToLower()}")"
                               value="@theme"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme.ToLower()}")">@theme</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Font Size</h6>
                @foreach (var size in _fontSizes)
                {
                    <div class="form-check form-check-inline">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size.ToLower()}")"
                               value="@size"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size.ToLower()}")">@size</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Language</h6>
                <select class="form-select" style="max-width: 300px;"
                        @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang.Key">@lang.Value</option>
                    }
                </select>
            </div>

            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
        </div>

        <div class="col-md-5">
            <h6>Live Preview</h6>
            <div class="preview-area @PreviewThemeClass" style="font-size: @PreviewFontSize; padding: @PreviewPadding;">
                <div class="preview-header">
                    <strong>Sample Header</strong>
                </div>
                <p class="preview-body">
                    This is how your content will look with the selected appearance settings.
                    The <em>@_theme</em> theme is applied with <strong>@_fontSize</strong> font size.
                </p>
                <div class="preview-nav">
                    <span class="preview-link">Dashboard</span>
                    <span class="preview-link">Settings</span>
                    <span class="preview-link">Help</span>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;

    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly Dictionary<string, string> _languages = new()
    {
        ["en"] = "English",
        ["es"] = "Español",
        ["fr"] = "Français",
        ["de"] = "Deutsch",
        ["ja"] = "日本語",
    };

    private string PreviewThemeClass => _theme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string PreviewFontSize => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private string PreviewPadding => _compactMode ? "0.5rem" : "1rem";

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _statusMessage = "Appearance settings saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}
