.preview-area {
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 0.5rem;
    transition: all 0.2s;
    min-height: 180px;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
}

.preview-header {
    margin-bottom: 0.5rem;
    padding-bottom: 0.5rem;
    border-bottom: 1px solid rgba(128, 128, 128, 0.3);
}

.preview-body {
    margin-bottom: 0.5rem;
}

.preview-nav {
    display: flex;
    gap: 1rem;
}

.preview-link {
    color: var(--bs-primary, #0d6efd);
    cursor: default;
    font-size: 0.9em;
}

.preview-dark .preview-link {
    color: #89b4fa;
}

