arguments.file_text:
@page "/settings"
@rendermode InteractiveServer
@namespace sv_a2434daba9ac4eb287d556620d61403a.Components.Pages.Settings

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection"
                     OnSectionChanged="section => _activeSection = section" />

    <main class="settings-content">
        @switch (_activeSection)
        {
            case "profile":
                <ProfileSettings />
                break;
            case "notifications":
                <NotificationSettings />
                break;
            case "security":
                <SecuritySettings />
                break;
            case "appearance":
                <AppearanceSettings />
                break;
        }
    </main>
</div>

@code {
    private string _activeSection = "profile";
}

.settings-layout {
    display: flex;
    min-height: calc(100vh - 70px);
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 0.5rem;
    overflow: hidden;
    margin: 1rem;
    background: var(--bs-body-bg, #fff);
}

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

